import asyncio
import json
import logging
import secrets
from dataclasses import dataclass, field
from typing import Dict, Optional, Set, Any

import websockets
from websockets.server import WebSocketServerProtocol

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger("mmo_server")


@dataclass
class Item:
    item_id: str
    name: str
    owner_id: str


@dataclass
class Player:
    player_id: str
    ws: WebSocketServerProtocol
    inventory: Set[str] = field(default_factory=set)
    lock: asyncio.Lock = field(default_factory=asyncio.Lock)


class GameServer:
    def __init__(self):
        self.players: Dict[str, Player] = {}
        self.items: Dict[str, Item] = {}
        self.global_lock = asyncio.Lock()

    async def register(self, ws: WebSocketServerProtocol) -> str:
        player_id = secrets.token_hex(8)
        player = Player(player_id=player_id, ws=ws)
        async with self.global_lock:
            self.players[player_id] = player
        await self.send(ws, {"type": "welcome", "player_id": player_id})
        logger.info("Player connected: %s", player_id)
        return player_id

    async def unregister(self, player_id: str):
        async with self.global_lock:
            player = self.players.pop(player_id, None)
        if player:
            logger.info("Player disconnected: %s", player_id)

    async def send(self, ws: WebSocketServerProtocol, message: Dict[str, Any]):
        await ws.send(json.dumps(message))

    async def broadcast(self, message: Dict[str, Any]):
        data = json.dumps(message)
        async with self.global_lock:
            players = list(self.players.values())
        await asyncio.gather(*(p.ws.send(data) for p in players), return_exceptions=True)

    async def create_item(self, owner_id: str, name: str) -> Item:
        item_id = secrets.token_hex(12)
        item = Item(item_id=item_id, name=name, owner_id=owner_id)
        async with self.global_lock:
            self.items[item_id] = item
            player = self.players.get(owner_id)
            if player:
                player.inventory.add(item_id)
        return item

    async def get_state(self, player_id: str) -> Dict[str, Any]:
        async with self.global_lock:
            player = self.players.get(player_id)
            if not player:
                return {"error": "player_not_found"}
            inventory = []
            for item_id in player.inventory:
                item = self.items.get(item_id)
                if item:
                    inventory.append({"item_id": item.item_id, "name": item.name, "owner_id": item.owner_id})
            return {"type": "state", "player_id": player_id, "inventory": inventory}

    async def transfer_item(self, from_id: str, to_id: str, item_id: str) -> Dict[str, Any]:
        if from_id == to_id:
            return {"error": "cannot_transfer_to_self"}

        first_id, second_id = sorted([from_id, to_id])
        async with self.global_lock:
            from_player = self.players.get(from_id)
            to_player = self.players.get(to_id)
            item = self.items.get(item_id)

            if not from_player or not to_player:
                return {"error": "player_not_found"}
            if not item:
                return {"error": "item_not_found"}
            if item.owner_id != from_id:
                return {"error": "not_item_owner"}
            if item_id not in from_player.inventory:
                return {"error": "item_not_in_inventory"}

            async with from_player.lock:
                async with to_player.lock:
                    if item.owner_id != from_id or item_id not in from_player.inventory:
                        return {"error": "concurrent_transfer_conflict"}

                    from_player.inventory.remove(item_id)
                    to_player.inventory.add(item_id)
                    item.owner_id = to_id

        await self.send(from_player.ws, {
            "type": "item_transferred_out",
            "item_id": item_id,
            "to_player_id": to_id
        })
        await self.send(to_player.ws, {
            "type": "item_transferred_in",
            "item_id": item_id,
            "from_player_id": from_id
        })
        return {"type": "transfer_ok", "item_id": item_id, "from_player_id": from_id, "to_player_id": to_id}

    async def handle_message(self, player_id: str, message: Dict[str, Any]):
        msg_type = message.get("type")
        if msg_type == "get_state":
            state = await self.get_state(player_id)
            player = self.players.get(player_id)
            if player:
                await self.send(player.ws, state)
        elif msg_type == "create_item":
            name = message.get("name", "Unknown Item")
            item = await self.create_item(player_id, name)
            player = self.players.get(player_id)
            if player:
                await self.send(player.ws, {
                    "type": "item_created",
                    "item": {"item_id": item.item_id, "name": item.name, "owner_id": item.owner_id}
                })
        elif msg_type == "transfer_item":
            to_player_id = message.get("to_player_id")
            item_id = message.get("item_id")
            if not to_player_id or not item_id:
                player = self.players.get(player_id)
                if player:
                    await self.send(player.ws, {"error": "missing_fields"})
                return
            result = await self.transfer_item(player_id, to_player_id, item_id)
            player = self.players.get(player_id)
            if player:
                await self.send(player.ws, result)
        else:
            player = self.players.get(player_id)
            if player:
                await self.send(player.ws, {"error": "unknown_message_type"})

    async def handler(self, ws: WebSocketServerProtocol):
        player_id = await self.register(ws)
        try:
            async for raw in ws:
                try:
                    message = json.loads(raw)
                except json.JSONDecodeError:
                    await self.send(ws, {"error": "invalid_json"})
                    continue
                await self.handle_message(player_id, message)
        except websockets.ConnectionClosed:
            pass
        finally:
            await self.unregister(player_id)


async def main():
    server = GameServer()

    async def seed_world():
        while True:
            await asyncio.sleep(30)
            async with server.global_lock:
                player_ids = list(server.players.keys())
            if player_ids:
                owner_id = player_ids[0]
                await server.create_item(owner_id, "Starter Potion")

    asyncio.create_task(seed_world())

    async with websockets.serve(server.handler, "0.0.0.0", 8765, ping_interval=20, ping_timeout=20):
        logger.info("MMO game server running on ws://0.0.0.0:8765")
        await asyncio.Future()


if __name__ == "__main__":
    asyncio.run(main())